import { applyColorRuleToSingleValue } from './apply-color-rule-to-single-value.js';
import { type ColorRuleProps } from '../../../types/color-rule.js';
import { DEFAULT_SINGLE_VALUE_COLOR } from '../constants.js';

export const getCalculatedColor = (
  data: number | string,
  colorRules?: ColorRuleProps[],
  explicitColor?: string,
  dataItem?: Record<string, unknown>,
): { color: string; ruleApplied: boolean } => {
  if (colorRules && colorRules.length > 0) {
    const ruleColor = applyColorRuleToSingleValue(colorRules, data, dataItem);
    if (ruleColor) {
      return { color: ruleColor, ruleApplied: true };
    }
  }

  if (explicitColor) {
    return { color: explicitColor, ruleApplied: false };
  }

  return { color: DEFAULT_SINGLE_VALUE_COLOR, ruleApplied: false };
};
